/* CRIAÇÃO DE TABELAS DA CAMADA GOLD (DIMENSIONAL) */

------ DIMENSÃO DEPUTADO ------
CREATE TABLE gold.dim_deputado 
(
  "sk_deputado" int generated by default as identity not null,
  "id_deputado" int not null,
  "nm_depudado" text not null,
  "sg_sexo" text not null,
  "dt_nascimento" date not null,
  "sg_uf" text not null,
  "ds_escolaridade" text not null,
  "sg_partido" text not null,
  "ds_lider_partido" text not null,
  "ds_situacao" text not null,
  "ds_condicao_eleitoral" text not null,
  "cd_legislatura" int not null,
  "dt_inicio_legislatura" date not null,
  "dt_fim_legislatura" date not null,
  "dt_inicio_vigencia" date not null default current_date,
  "dt_fim_vigencia" date not null default '9999-12-31',
  "dh_ingestao" timestamp without time zone not null default current_timestamp,
  constraint dim_deputado_pkey primary key (sk_deputado)
) TABLESPACE pg_default;

/* INSERE REGISTROS DE CHAVE SUBSTITUTA DE DIMENSÃO */
INSERT INTO gold.dim_deputado
("sk_deputado" , "id_deputado", "nm_depudado", "sg_sexo", "dt_nascimento", "sg_uf", "ds_escolaridade" , "sg_partido", "ds_lider_partido", "ds_situacao", "ds_condicao_eleitoral", "cd_legislatura", "dt_inicio_legislatura", "dt_fim_legislatura", "dt_inicio_vigencia", "dt_fim_vigencia", "dh_ingestao")
VALUES
(-1, -1, 'NÃO INFORMADO', 'N/I', '9999-12-31', 'N/I', 'NÃO INFORMADO', 'N/I', 'NÃO INFORMADO', 'NÃO INFORMADO', 'NÃO INFORMADO', -1, '9999-12-31', '9999-12-31', current_date, '9999-12-31', current_timestamp),
(-3, -3, 'NÃO SE APLICA', 'N/A', '9999-12-31', 'N/A', 'NÃO SE APLICA', 'N/A', 'NÃO SE APLICA', 'NÃO SE APLICA', 'NÃO SE APLICA', -3, '9999-12-31', '9999-12-31', current_date, '9999-12-31', current_timestamp)
----------------------

