----- FATO PROPOSICAO -----
CREATE TABLE gold.ft_proposicao 
(
  "sk_deputado" int not null,
  "sk_orgao" int not null,
  "sk_proposicao" int not null,
  "sk_data_proposicao" int not null,
  "qtd_proposicao" int not null,
  "dh_ingestao" timestamp without time zone not null default current_timestamp,
  constraint ft_proposicao_pkey primary key (sk_deputado, sk_orgao, sk_proposicao, sk_data_proposicao)
) TABLESPACE pg_default;
---------------------

------ FATO VOTO ------
CREATE TABLE gold.ft_voto 
(
  "sk_votacao" int not null,
  "sk_deputado" int not null,
  "sk_orgao" int not null,
  "sk_evento" int not null,
  "sk_data_voto" int not null,
  "sk_proposicao" int not null, 
  "tp_voto" text not null, -- dimensão degenerada (DD)
  "qtd_voto" int not null,
   "dh_ingestao" timestamp without time zone not null default current_timestamp,
   constraint ft_voto_pkey primary key (sk_votacao, sk_deputado, sk_orgao, sk_evento, sk_data_voto, sk_proposicao, tp_voto)
) TABLESPACE pg_default; 
-----------------------

------ FATO DESPESA ------
CREATE TABLE gold.ft_despesa 
(
  "sk_deputado" int not null,  
  "sk_data_despesa" int not null,
  "tp_despesa" text not null, -- dimensão degenerada (DD)
  "vl_bruto" decimal not null ,
  "vl_liquido" decimal not null,
  "vl_glosa" decimal not null,
  "nr_parcela" int not null,
  "dh_ingestao" timestamp without time zone not null default current_timestamp,
  constraint ft_despesa_pkey primary key (sk_deputado, sk_data_despesa, tp_despesa)
) TABLESPACE pg_default; 
--------------------------


